+    fn alt_ctrl_key_combinations() {
+        let mut parser = InputParser::new();
+
+        // ESC + Ctrl+A (0x01) -> Alt+Ctrl+A
+        let events = parser.parse(&[0x1B, 0x01]);
+        assert_eq!(events.len(), 1);
